"use strict";(globalThis.webpackChunklearn_design_patterns_docs=globalThis.webpackChunklearn_design_patterns_docs||[]).push([[4345],{59596(n,t,e){e.r(t),e.d(t,{assets:()=>d,contentTitle:()=>o,default:()=>u,frontMatter:()=>i,metadata:()=>r,toc:()=>c});const r=JSON.parse('{"id":"single-responsibility/decorator/code","title":"\u6e90\u4ee3\u7801","description":"Decorator \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801","source":"@site/docs/02-single-responsibility/decorator/code.md","sourceDirName":"02-single-responsibility/decorator","slug":"/single-responsibility/decorator/code","permalink":"/LearnDesignPatterns/docs/single-responsibility/decorator/code","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":2,"frontMatter":{"sidebar_position":2,"title":"\u6e90\u4ee3\u7801","description":"Decorator \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},"sidebar":"docs","previous":{"title":"\u88c5\u9970\u5668\u6a21\u5f0f\uff08Decorator Pattern\uff09","permalink":"/LearnDesignPatterns/docs/single-responsibility/decorator/"},"next":{"title":"\u6865\u63a5\u6a21\u5f0f\uff08Bridge Pattern\uff09","permalink":"/LearnDesignPatterns/docs/single-responsibility/bridge/"}}');var s=e(74848),a=e(28453);const i={sidebar_position:2,title:"\u6e90\u4ee3\u7801",description:"Decorator \u6a21\u5f0f\u7684\u5b8c\u6574\u5b9e\u73b0\u4ee3\u7801"},o="\u6e90\u4ee3\u7801",d={},c=[{value:"\u5934\u6587\u4ef6\uff08Decorator.h\uff09",id:"\u5934\u6587\u4ef6decoratorh",level:2},{value:"\u5b9e\u73b0\u6587\u4ef6\uff08Decorator.cpp\uff09",id:"\u5b9e\u73b0\u6587\u4ef6decoratorcpp",level:2},{value:"\u6784\u5efa\u65b9\u5f0f",id:"\u6784\u5efa\u65b9\u5f0f",level:2}];function m(n){const t={admonition:"admonition",code:"code",h1:"h1",h2:"h2",header:"header",pre:"pre",...(0,a.R)(),...n.components};return(0,s.jsxs)(s.Fragment,{children:[(0,s.jsx)(t.header,{children:(0,s.jsx)(t.h1,{id:"\u6e90\u4ee3\u7801",children:"\u6e90\u4ee3\u7801"})}),"\n",(0,s.jsx)(t.h2,{id:"\u5934\u6587\u4ef6decoratorh",children:"\u5934\u6587\u4ef6\uff08Decorator.h\uff09"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="Decorator.h" showLineNumbers',children:"#ifndef DECORATOR_H\n#define DECORATOR_H\n\n#include <memory>\n#include <string>\n#include <vector>\n\n// ============================================================\n// \u88c5\u9970\u5668\u6a21\u5f0f - \u6570\u636e\u6d41\u5904\u7406\n// \u6838\u5fc3\u601d\u60f3\uff1a\u901a\u8fc7\u7ec4\u5408\u800c\u975e\u7ee7\u627f\uff0c\u52a8\u6001\u5730\u7ed9\u5bf9\u8c61\u6dfb\u52a0\u804c\u8d23\n// \u6bcf\u4e2a\u88c5\u9970\u5668\u53ea\u8d1f\u8d23\u4e00\u79cd\u589e\u5f3a\u529f\u80fd\uff08\u5355\u4e00\u804c\u8d23\uff09\n// ============================================================\n\n// \u62bd\u8c61\u7ec4\u4ef6\uff1a\u6570\u636e\u6d41\u63a5\u53e3\n// \u5b9a\u4e49\u8bfb\u5199\u64cd\u4f5c\u7684\u7edf\u4e00\u63a5\u53e3\uff0c\u88c5\u9970\u5668\u548c\u5177\u4f53\u6d41\u90fd\u5b9e\u73b0\u6b64\u63a5\u53e3\nclass DataStream {\npublic:\n    virtual ~DataStream() = default;\n    virtual std::string read() = 0;\n    virtual void write(const std::string& data) = 0;\n    virtual std::string getDescription() const = 0;\n};\n\n// \u5177\u4f53\u7ec4\u4ef6\uff1a\u6587\u4ef6\u6570\u636e\u6d41\n// \u6700\u57fa\u7840\u7684\u6570\u636e\u6d41\u5b9e\u73b0\uff0c\u63d0\u4f9b\u771f\u5b9e\u7684\u8bfb\u5199\u80fd\u529b\nclass FileStream : public DataStream {\npublic:\n    explicit FileStream(const std::string& filename);\n    std::string read() override;\n    void write(const std::string& data) override;\n    std::string getDescription() const override;\n\nprivate:\n    std::string filename_;\n    std::string buffer_;  // \u6a21\u62df\u6587\u4ef6\u5185\u5bb9\n};\n\n// \u5177\u4f53\u7ec4\u4ef6\uff1a\u5185\u5b58\u6570\u636e\u6d41\nclass MemoryStream : public DataStream {\npublic:\n    MemoryStream();\n    std::string read() override;\n    void write(const std::string& data) override;\n    std::string getDescription() const override;\n\nprivate:\n    std::string buffer_;\n};\n\n// \u88c5\u9970\u5668\u57fa\u7c7b\n// \u5173\u952e\u8bbe\u8ba1\uff1a\u6301\u6709\u4e00\u4e2aDataStream\u7684\u667a\u80fd\u6307\u9488\uff0c\u8f6c\u53d1\u6240\u6709\u8c03\u7528\u7ed9\u88ab\u88c5\u9970\u5bf9\u8c61\n// \u8fd9\u662f\u88c5\u9970\u5668\u6a21\u5f0f\u7684\u6838\u5fc3\u2014\u2014\u88c5\u9970\u5668\u672c\u8eab\u4e5f\u662fDataStream\uff0c\u53ef\u4ee5\u88ab\u7ee7\u7eed\u88c5\u9970\nclass StreamDecorator : public DataStream {\npublic:\n    explicit StreamDecorator(std::unique_ptr<DataStream> stream);\n    std::string read() override;\n    void write(const std::string& data) override;\n    std::string getDescription() const override;\n\nprotected:\n    std::unique_ptr<DataStream> wrappedStream_;  // \u88ab\u88c5\u9970\u7684\u6d41\u5bf9\u8c61\n};\n\n// \u5177\u4f53\u88c5\u9970\u5668\uff1a\u52a0\u5bc6\u6d41\n// \u53ea\u8d1f\u8d23\u52a0\u5bc6/\u89e3\u5bc6\u8fd9\u4e00\u4ef6\u4e8b\uff08\u5355\u4e00\u804c\u8d23\uff09\nclass EncryptionStream : public StreamDecorator {\npublic:\n    explicit EncryptionStream(std::unique_ptr<DataStream> stream, int key = 3);\n    std::string read() override;\n    void write(const std::string& data) override;\n    std::string getDescription() const override;\n\nprivate:\n    int key_;  // \u7b80\u5355\u7684\u51ef\u6492\u5bc6\u7801\u504f\u79fb\u91cf\n    std::string encrypt(const std::string& data) const;\n    std::string decrypt(const std::string& data) const;\n};\n\n// \u5177\u4f53\u88c5\u9970\u5668\uff1a\u538b\u7f29\u6d41\n// \u53ea\u8d1f\u8d23\u538b\u7f29/\u89e3\u538b\u8fd9\u4e00\u4ef6\u4e8b\nclass CompressionStream : public StreamDecorator {\npublic:\n    explicit CompressionStream(std::unique_ptr<DataStream> stream);\n    std::string read() override;\n    void write(const std::string& data) override;\n    std::string getDescription() const override;\n\nprivate:\n    // \u7b80\u5355\u7684\u6e38\u7a0b\u7f16\u7801\uff08RLE\uff09\u538b\u7f29\n    std::string compress(const std::string& data) const;\n    std::string decompress(const std::string& data) const;\n};\n\n// \u5177\u4f53\u88c5\u9970\u5668\uff1a\u7f13\u51b2\u6d41\n// \u53ea\u8d1f\u8d23\u7f13\u51b2\u7ba1\u7406\u8fd9\u4e00\u4ef6\u4e8b\uff0c\u7d2f\u79ef\u5230\u9608\u503c\u540e\u624d\u771f\u6b63\u5199\u5165\nclass BufferedStream : public StreamDecorator {\npublic:\n    explicit BufferedStream(std::unique_ptr<DataStream> stream,\n                            std::size_t bufferSize = 64);\n    ~BufferedStream() override;\n    std::string read() override;\n    void write(const std::string& data) override;\n    void flush();\n    std::string getDescription() const override;\n\nprivate:\n    std::size_t bufferSize_;\n    std::string pendingBuffer_;  // \u5f85\u5199\u5165\u7684\u7f13\u51b2\u6570\u636e\n};\n\n#endif // DECORATOR_H\n"})}),"\n",(0,s.jsx)(t.h2,{id:"\u5b9e\u73b0\u6587\u4ef6decoratorcpp",children:"\u5b9e\u73b0\u6587\u4ef6\uff08Decorator.cpp\uff09"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cpp",metastring:'title="Decorator.cpp" showLineNumbers',children:'#include "Decorator.h"\n#include <iostream>\n#include <algorithm>\n#include <sstream>\n\n// ============================================================\n// FileStream \u5b9e\u73b0\n// ============================================================\n\nFileStream::FileStream(const std::string& filename)\n    : filename_(filename) {}\n\nstd::string FileStream::read() {\n    // \u6a21\u62df\u4ece\u6587\u4ef6\u8bfb\u53d6\u6570\u636e\n    std::cout << "  [FileStream] \u4ece\u6587\u4ef6 \\"" << filename_ << "\\" \u8bfb\u53d6\u6570\u636e\\n";\n    return buffer_;\n}\n\nvoid FileStream::write(const std::string& data) {\n    // \u6a21\u62df\u5199\u5165\u6587\u4ef6\n    std::cout << "  [FileStream] \u5199\u5165\u6570\u636e\u5230\u6587\u4ef6 \\"" << filename_ << "\\"\\n";\n    buffer_ = data;\n}\n\nstd::string FileStream::getDescription() const {\n    return "FileStream(" + filename_ + ")";\n}\n\n// ============================================================\n// MemoryStream \u5b9e\u73b0\n// ============================================================\n\nMemoryStream::MemoryStream() = default;\n\nstd::string MemoryStream::read() {\n    std::cout << "  [MemoryStream] \u4ece\u5185\u5b58\u8bfb\u53d6\u6570\u636e\\n";\n    return buffer_;\n}\n\nvoid MemoryStream::write(const std::string& data) {\n    std::cout << "  [MemoryStream] \u5199\u5165\u6570\u636e\u5230\u5185\u5b58\\n";\n    buffer_ = data;\n}\n\nstd::string MemoryStream::getDescription() const {\n    return "MemoryStream";\n}\n\n// ============================================================\n// StreamDecorator \u57fa\u7c7b\u5b9e\u73b0\n// \u9ed8\u8ba4\u884c\u4e3a\uff1a\u76f4\u63a5\u8f6c\u53d1\u7ed9\u88ab\u88c5\u9970\u5bf9\u8c61\n// ============================================================\n\nStreamDecorator::StreamDecorator(std::unique_ptr<DataStream> stream)\n    : wrappedStream_(std::move(stream)) {}\n\nstd::string StreamDecorator::read() {\n    return wrappedStream_->read();\n}\n\nvoid StreamDecorator::write(const std::string& data) {\n    wrappedStream_->write(data);\n}\n\nstd::string StreamDecorator::getDescription() const {\n    return wrappedStream_->getDescription();\n}\n\n// ============================================================\n// EncryptionStream \u5b9e\u73b0\n// \u4f7f\u7528\u7b80\u5355\u7684\u51ef\u6492\u5bc6\u7801\u6765\u6f14\u793a\u52a0\u5bc6/\u89e3\u5bc6\u8fc7\u7a0b\n// ============================================================\n\nEncryptionStream::EncryptionStream(std::unique_ptr<DataStream> stream, int key)\n    : StreamDecorator(std::move(stream)), key_(key) {}\n\nstd::string EncryptionStream::encrypt(const std::string& data) const {\n    std::string result = data;\n    for (auto& ch : result) {\n        // \u53ea\u5bf9\u53ef\u6253\u5370ASCII\u5b57\u7b26\uff0833~126\uff09\u505a\u504f\u79fb\uff0c\u4fdd\u6301\u7a7a\u683c\u4e0d\u53d8\n        if (ch >= 33 && ch <= 126) {\n            ch = static_cast<char>((ch - 33 + key_) % 94 + 33);\n        }\n    }\n    return result;\n}\n\nstd::string EncryptionStream::decrypt(const std::string& data) const {\n    std::string result = data;\n    for (auto& ch : result) {\n        if (ch >= 33 && ch <= 126) {\n            ch = static_cast<char>((ch - 33 - key_ + 94) % 94 + 33);\n        }\n    }\n    return result;\n}\n\nstd::string EncryptionStream::read() {\n    // \u8bfb\u53d6\u65f6\u5148\u4ece\u5185\u5c42\u6d41\u8bfb\u53d6\uff0c\u7136\u540e\u89e3\u5bc6\n    std::string data = wrappedStream_->read();\n    std::cout << "  [Encryption] \u89e3\u5bc6\u6570\u636e: \\"" << data << "\\"\\n";\n    std::string decrypted = decrypt(data);\n    std::cout << "  [Encryption] \u89e3\u5bc6\u7ed3\u679c: \\"" << decrypted << "\\"\\n";\n    return decrypted;\n}\n\nvoid EncryptionStream::write(const std::string& data) {\n    // \u5199\u5165\u65f6\u5148\u52a0\u5bc6\uff0c\u7136\u540e\u4f20\u7ed9\u5185\u5c42\u6d41\n    std::cout << "  [Encryption] \u52a0\u5bc6\u6570\u636e: \\"" << data << "\\"\\n";\n    std::string encrypted = encrypt(data);\n    std::cout << "  [Encryption] \u52a0\u5bc6\u7ed3\u679c: \\"" << encrypted << "\\"\\n";\n    wrappedStream_->write(encrypted);\n}\n\nstd::string EncryptionStream::getDescription() const {\n    return "Encryption -> " + wrappedStream_->getDescription();\n}\n\n// ============================================================\n// CompressionStream \u5b9e\u73b0\n// \u4f7f\u7528\u7b80\u5355\u7684\u6e38\u7a0b\u7f16\u7801\uff08Run-Length Encoding\uff09\n// ============================================================\n\nCompressionStream::CompressionStream(std::unique_ptr<DataStream> stream)\n    : StreamDecorator(std::move(stream)) {}\n\nstd::string CompressionStream::compress(const std::string& data) const {\n    if (data.empty()) return data;\n\n    std::ostringstream oss;\n    char current = data[0];\n    int count = 1;\n\n    for (std::size_t i = 1; i < data.size(); ++i) {\n        if (data[i] == current) {\n            ++count;\n        } else {\n            oss << current;\n            if (count > 1) oss << count;\n            current = data[i];\n            count = 1;\n        }\n    }\n    oss << current;\n    if (count > 1) oss << count;\n    return oss.str();\n}\n\nstd::string CompressionStream::decompress(const std::string& data) const {\n    if (data.empty()) return data;\n\n    std::ostringstream oss;\n    for (std::size_t i = 0; i < data.size(); ++i) {\n        if (std::isdigit(static_cast<unsigned char>(data[i]))) {\n            // \u6570\u5b57\u8868\u793a\u524d\u4e00\u4e2a\u5b57\u7b26\u91cd\u590d\u7684\u6b21\u6570\n            int count = data[i] - \'0\';\n            if (!oss.str().empty()) {\n                char lastChar = oss.str().back();\n                // \u5df2\u7ecf\u8f93\u51fa\u4e86\u4e00\u6b21\uff0c\u518d\u8f93\u51fa count-1 \u6b21\n                for (int j = 1; j < count; ++j) {\n                    oss << lastChar;\n                }\n            }\n        } else {\n            oss << data[i];\n        }\n    }\n    return oss.str();\n}\n\nstd::string CompressionStream::read() {\n    std::string data = wrappedStream_->read();\n    std::cout << "  [Compression] \u89e3\u538b\u6570\u636e: \\"" << data << "\\"\\n";\n    std::string decompressed = decompress(data);\n    std::cout << "  [Compression] \u89e3\u538b\u7ed3\u679c: \\"" << decompressed << "\\"\\n";\n    return decompressed;\n}\n\nvoid CompressionStream::write(const std::string& data) {\n    std::cout << "  [Compression] \u538b\u7f29\u6570\u636e: \\"" << data << "\\"\\n";\n    std::string compressed = compress(data);\n    std::cout << "  [Compression] \u538b\u7f29\u7ed3\u679c: \\"" << compressed << "\\"\\n";\n    wrappedStream_->write(compressed);\n}\n\nstd::string CompressionStream::getDescription() const {\n    return "Compression -> " + wrappedStream_->getDescription();\n}\n\n// ============================================================\n// BufferedStream \u5b9e\u73b0\n// ============================================================\n\nBufferedStream::BufferedStream(std::unique_ptr<DataStream> stream,\n                               std::size_t bufferSize)\n    : StreamDecorator(std::move(stream)), bufferSize_(bufferSize) {}\n\nBufferedStream::~BufferedStream() {\n    // \u6790\u6784\u65f6\u81ea\u52a8\u5237\u65b0\u672a\u5199\u5165\u7684\u6570\u636e\uff0c\u907f\u514d\u6570\u636e\u4e22\u5931\n    if (!pendingBuffer_.empty()) {\n        flush();\n    }\n}\n\nstd::string BufferedStream::read() {\n    std::cout << "  [Buffered] \u901a\u8fc7\u7f13\u51b2\u533a\u8bfb\u53d6\u6570\u636e\\n";\n    return wrappedStream_->read();\n}\n\nvoid BufferedStream::write(const std::string& data) {\n    pendingBuffer_ += data;\n    std::cout << "  [Buffered] \u7f13\u51b2\u6570\u636e (\u5f53\u524d\u7f13\u51b2\u533a: "\n              << pendingBuffer_.size() << "/" << bufferSize_ << " \u5b57\u8282)\\n";\n\n    // \u5f53\u7f13\u51b2\u533a\u6ee1\u65f6\u81ea\u52a8\u5237\u65b0\n    if (pendingBuffer_.size() >= bufferSize_) {\n        flush();\n    }\n}\n\nvoid BufferedStream::flush() {\n    if (!pendingBuffer_.empty()) {\n        std::cout << "  [Buffered] \u5237\u65b0\u7f13\u51b2\u533a\uff0c\u5199\u5165 "\n                  << pendingBuffer_.size() << " \u5b57\u8282\\n";\n        wrappedStream_->write(pendingBuffer_);\n        pendingBuffer_.clear();\n    }\n}\n\nstd::string BufferedStream::getDescription() const {\n    return "Buffered(" + std::to_string(bufferSize_) + ") -> "\n           + wrappedStream_->getDescription();\n}\n\n// ============================================================\n// \u6f14\u793a\u7a0b\u5e8f\n// ============================================================\n\nint main() {\n    std::cout << "========================================\\n";\n    std::cout << "   \u88c5\u9970\u5668\u6a21\u5f0f - \u6570\u636e\u6d41\u5904\u7406\u6f14\u793a\\n";\n    std::cout << "========================================\\n\\n";\n\n    // \u573a\u666f1\uff1a\u57fa\u7840\u6587\u4ef6\u6d41\uff08\u65e0\u88c5\u9970\uff09\n    std::cout << "--- \u573a\u666f1: \u57fa\u7840\u6587\u4ef6\u6d41 ---\\n";\n    {\n        auto stream = std::make_unique<FileStream>("data.txt");\n        std::cout << "\u6d41\u63cf\u8ff0: " << stream->getDescription() << "\\n";\n        stream->write("Hello World");\n        std::string result = stream->read();\n        std::cout << "\u8bfb\u53d6\u7ed3\u679c: \\"" << result << "\\"\\n\\n";\n    }\n\n    // \u573a\u666f2\uff1a\u6587\u4ef6\u6d41 + \u52a0\u5bc6\u88c5\u9970\n    std::cout << "--- \u573a\u666f2: \u52a0\u5bc6\u6587\u4ef6\u6d41 ---\\n";\n    {\n        // \u88c5\u9970\u5668\u5c42\u5c42\u5305\u88f9\uff1aFileStream\u88abEncryptionStream\u88c5\u9970\n        auto stream = std::make_unique<EncryptionStream>(\n            std::make_unique<FileStream>("secret.dat"), 5);\n        std::cout << "\u6d41\u63cf\u8ff0: " << stream->getDescription() << "\\n";\n        stream->write("Sensitive Data");\n        std::string result = stream->read();\n        std::cout << "\u8bfb\u53d6\u7ed3\u679c: \\"" << result << "\\"\\n\\n";\n    }\n\n    // \u573a\u666f3\uff1a\u591a\u5c42\u88c5\u9970\u53e0\u52a0\u2014\u2014\u538b\u7f29 + \u52a0\u5bc6 + \u6587\u4ef6\u6d41\n    // \u5199\u5165\u987a\u5e8f\uff1a\u539f\u59cb\u6570\u636e -> \u538b\u7f29 -> \u52a0\u5bc6 -> \u6587\u4ef6\n    // \u8bfb\u53d6\u987a\u5e8f\uff1a\u6587\u4ef6 -> \u89e3\u5bc6 -> \u89e3\u538b -> \u539f\u59cb\u6570\u636e\n    std::cout << "--- \u573a\u666f3: \u538b\u7f29 + \u52a0\u5bc6 \u53e0\u52a0\u88c5\u9970 ---\\n";\n    {\n        auto stream = std::make_unique<CompressionStream>(\n            std::make_unique<EncryptionStream>(\n                std::make_unique<FileStream>("archive.enc"), 3));\n        std::cout << "\u6d41\u63cf\u8ff0: " << stream->getDescription() << "\\n";\n        stream->write("aaabbbcccddd");\n        std::string result = stream->read();\n        std::cout << "\u8bfb\u53d6\u7ed3\u679c: \\"" << result << "\\"\\n\\n";\n    }\n\n    // \u573a\u666f4\uff1a\u7f13\u51b2 + \u52a0\u5bc6 + \u5185\u5b58\u6d41\n    std::cout << "--- \u573a\u666f4: \u7f13\u51b2 + \u52a0\u5bc6 + \u5185\u5b58\u6d41 ---\\n";\n    {\n        // \u8bbe\u7f6e\u8f83\u5c0f\u7684\u7f13\u51b2\u533a\u5927\u5c0f\u4ee5\u4fbf\u6f14\u793a\n        auto rawStream = std::make_unique<BufferedStream>(\n            std::make_unique<EncryptionStream>(\n                std::make_unique<MemoryStream>(), 2),\n            30);  // 30\u5b57\u8282\u7f13\u51b2\u533a\n        std::cout << "\u6d41\u63cf\u8ff0: " << rawStream->getDescription() << "\\n";\n\n        // \u591a\u6b21\u5199\u5165\u5c0f\u6570\u636e\uff0c\u89c2\u5bdf\u7f13\u51b2\u884c\u4e3a\n        rawStream->write("First chunk. ");\n        rawStream->write("Second chunk. ");\n        rawStream->write("Third chunk.");  // \u5e94\u89e6\u53d1\u7f13\u51b2\u533a\u5237\u65b0\n\n        // \u624b\u52a8\u5237\u65b0\u5269\u4f59\u6570\u636e\n        rawStream->flush();\n        std::string result = rawStream->read();\n        std::cout << "\u8bfb\u53d6\u7ed3\u679c: \\"" << result << "\\"\\n\\n";\n    }\n\n    // \u573a\u666f5\uff1a\u5c55\u793a\u88c5\u9970\u5668\u7684\u7075\u6d3b\u6027\u2014\u2014\u8fd0\u884c\u65f6\u52a8\u6001\u7ec4\u5408\n    std::cout << "--- \u573a\u666f5: \u8fd0\u884c\u65f6\u52a8\u6001\u7ec4\u5408\u88c5\u9970\u5668 ---\\n";\n    {\n        // \u6839\u636e"\u914d\u7f6e"\u52a8\u6001\u51b3\u5b9a\u662f\u5426\u542f\u7528\u5404\u79cd\u529f\u80fd\n        bool enableEncryption = true;\n        bool enableCompression = true;\n        bool enableBuffering = true;\n\n        std::unique_ptr<DataStream> stream =\n            std::make_unique<MemoryStream>();\n\n        if (enableBuffering) {\n            stream = std::make_unique<BufferedStream>(\n                std::move(stream), 20);  // \u5c0f\u7f13\u51b2\u533a\uff0c\u5199\u5165\u65f6\u81ea\u52a8\u5237\u65b0\n        }\n        if (enableEncryption) {\n            stream = std::make_unique<EncryptionStream>(\n                std::move(stream), 3);\n        }\n        if (enableCompression) {\n            stream = std::make_unique<CompressionStream>(\n                std::move(stream));\n        }\n\n        std::cout << "\u6d41\u63cf\u8ff0: " << stream->getDescription() << "\\n";\n        stream->write("Dynamic pipeline test data!");\n        std::string result = stream->read();\n        std::cout << "\u8bfb\u53d6\u7ed3\u679c: \\"" << result << "\\"\\n";\n    }\n\n    std::cout << "\\n========================================\\n";\n    std::cout << "   \u6f14\u793a\u7ed3\u675f\\n";\n    std::cout << "========================================\\n";\n\n    return 0;\n}\n'})}),"\n",(0,s.jsx)(t.h2,{id:"\u6784\u5efa\u65b9\u5f0f",children:"\u6784\u5efa\u65b9\u5f0f"}),"\n",(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-cmake",metastring:'title="CMakeLists.txt"',children:"cmake_minimum_required(VERSION 3.17)\nadd_executable(Pattern_Decorator Decorator.cpp Decorator.h)\ntarget_compile_features(Pattern_Decorator PRIVATE cxx_std_17)\n"})}),"\n",(0,s.jsx)(t.admonition,{title:"\u7f16\u8bd1\u8fd0\u884c",type:"tip",children:(0,s.jsx)(t.pre,{children:(0,s.jsx)(t.code,{className:"language-bash",children:"cd build\ncmake --build . --target Pattern_Decorator\n./Pattern_Decorator\n"})})})]})}function u(n={}){const{wrapper:t}={...(0,a.R)(),...n.components};return t?(0,s.jsx)(t,{...n,children:(0,s.jsx)(m,{...n})}):m(n)}},28453(n,t,e){e.d(t,{R:()=>i,x:()=>o});var r=e(96540);const s={},a=r.createContext(s);function i(n){const t=r.useContext(a);return r.useMemo(function(){return"function"==typeof n?n(t):{...t,...n}},[t,n])}function o(n){let t;return t=n.disableParentContext?"function"==typeof n.components?n.components(s):n.components||s:i(n.components),r.createElement(a.Provider,{value:t},n.children)}}}]);